const express = require('express');
const router = express.Router();

// Allowlist of safe redirect URLs
const ALLOWED_REDIRECTS = [
  '/dashboard',
  '/profile',
  '/account',
  '/home',
  '/settings'
];

// Helper function to validate redirect URL
function isValidRedirectUrl(url) {
  if (!url || typeof url !== 'string') return false;
  
  // Check if URL is a relative path and matches our allowlist
  if (url.startsWith('/')) {
    return ALLOWED_REDIRECTS.some(allowed => url.startsWith(allowed));
  }
  
  // For absolute URLs, check if they're from our domain
  try {
    const parsedUrl = new URL(url, 'http://localhost');
    return parsedUrl.hostname === 'localhost' || parsedUrl.hostname === 'yourdomain.com';
  } catch (error) {
    return false;
  }
}

router.get('/oauth/callback', (req, res) => {
  // Simulate OAuth authentication success
  const isAuthenticated = true;
  
  if (isAuthenticated) {
    const returnUrl = req.query.return_url;
    
    // Validate the return URL
    if (returnUrl && isValidRedirectUrl(returnUrl)) {
      return res.redirect(returnUrl);
    } else {
      // Fallback to default redirect if invalid or missing
      return res.redirect('/dashboard');
    }
  } else {
    // Handle authentication failure
    return res.redirect('/login?error=auth_failed');
  }
});

module.exports = router;